"use strict";const e=require("../utils/request.js");exports.getProfile=function(){return e.request({url:"/auth/profile",method:"GET"})},exports.login=function(t){return e.request({url:"/auth/login",method:"POST",data:{account:t.email,password:t.password}})},exports.logout=function(){return e.request({url:"/auth/logout",method:"POST"})},exports.register=function(t){return e.request({url:"/auth/register",method:"POST",data:t})},exports.sendCode=function(t){return e.request({url:"/auth/send-register-code",method:"POST",data:{email:t}})};
